class APIService {
    static let shared = APIService()
    private let client = HTTPClient.shared
    
    private let cloudAPIBaseURL = "https://api.example.com"
    
    private init() {}
    
    func fetchCloudData(endpoint: String, completion: @escaping (Result<APIResponse, HTTPClient.HTTPError>) -> Void) {
        let url = "\(cloudAPIBaseURL)/\(endpoint)"
        client.request(url: url, method: .GET, completion: completion)
    }
    
    func postCloudData(endpoint: String, data: [String: Any], completion: @escaping (Result<APIResponse, HTTPClient.HTTPError>) -> Void) {
        let url = "\(cloudAPIBaseURL)/\(endpoint)"
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: data) else {
            completion(.failure(.decodingError))
            return
        }
        
        client.request(url: url, method: .POST, body: jsonData, completion: completion)
    }
    
    func fetchDeviceStatus(deviceIP: String, completion: @escaping (Result<DeviceStatus, HTTPClient.HTTPError>) -> Void) {
        let url = "http://\(deviceIP)/status"
        client.request(url: url, method: .GET, completion: completion)
    }
    
    func sendDeviceCommand(deviceIP: String, command: DeviceCommand, completion: @escaping (Result<APIResponse, HTTPClient.HTTPError>) -> Void) {
        let url = "http://\(deviceIP)/command"
        
        guard let jsonData = try? JSONEncoder().encode(command) else {
            completion(.failure(.decodingError))
            return
        }
        
        client.request(url: url, method: .POST, body: jsonData, completion: completion)
    }
    
    func discoverDevices(subnet: String, completion: @escaping ([String]) -> Void) {
        var discoveredDevices: [String] = []
        let dispatchGroup = DispatchGroup()
        
        for i in 1...254 {
            let ip = "\(subnet).\(i)"
            dispatchGroup.enter()
            
            let url = "http://\(ip)/ping"
            client.requestData(url: url, method: .GET) { result in
                switch result {
                case .success:
                    discoveredDevices.append(ip)
                case .failure:
                    break
                }
                dispatchGroup.leave()
            }
        }
        
        dispatchGroup.notify(queue: .main) {
            completion(discoveredDevices)
        }
    }
}

